  'de',
  '{"name":"Sieon Choi","title":"IT Developer","headline":"Hallo, ich bin Sieon Choi — ich schaffe Technologie für eine gleichberechtigte Gesellschaft.","bioPoints":[{"emoji":"❤️","text":"Immer fröhlich und voller positiver Energie."},{"emoji":"🧡","text":"Legt Wert auf Verantwortungsbewusstsein und Verbundenheit mit Menschen."},{"emoji":"💛","text":"Strebt danach, ein Entwickler zu sein, der effiziente Logik aufbaut."},{"emoji":"💚","text":"Erfahrung in schneller, reibungsloser Kommunikation und Zusammenarbeit in Teamprojekten."}],"skills":["Java","Spring Boot","Python","TensorFlow","JavaScript","TypeScript","React","Oracle","MySQL","SQL","Git","SVN"],"contacts":[{"label":"Geboren","value":"19. Aug. 1999","icon":"🙆‍♂️"},{"label":"E-Mail","value":"noino0819@naver.com","url":"mailto:noino0819@naver.com","icon":"✉️"},{"label":"GitHub","value":"noino0819","url":"https://github.com/noino0819","icon":"😺","tooltip":"Schau dir mein GitHub an!"},{"label":"LinkedIn","value":"LinkedIn","url":"https://www.linkedin.com/in/%EC%8B%9C%EC%96%B8-%EC%B5%9C-77b9a5248/","icon":"💼"},{"label":"Blog","value":"NOINOs Alltags-Review","url":"https://blog.naver.com/noino0819","icon":"📝","tooltip":"Ein persönlicher Blog! Seit 2023 poste ich konsequent 5+ Tage pro Woche — ein Beweis meiner Beständigkeit."}]}',
