  '[{"category":"IT","categoryIcon":"💻","items":[{"name":"TensorFlow Developer Certificate","date":"2022.09.12"},{"name":"SQLD","date":"2025.06.27","detail":"SQLD-057014249 · KDATA"}]},{"category":"Sprachen","categoryIcon":"🗣️","items":[{"name":"TOEIC SPEAKING","date":"2025.12.08","detail":"Intermediate High (140) · YBM"}]},{"category":"Sonstiges","categoryIcon":"📖","items":[{"name":"MOS Master","date":"2018.06.18","detail":"YBM"}]}]',
  '[{"title":"KI-Gesundheitsberatungsplattform","period":"2023.11 - Gegenwart","affiliation":"Hyundai Futurenet","description":"Ein personalisiertes Ernährungs- und Lebensstil-Beratungssystem mit Gesundheitsdaten. Steigert die Beratungsqualität und Effizienz durch KI und Biodaten-Integration.","highlights":["Sitzungsbasierte Beratung pro Mitglied — Beratungshistorie und kontinuierliche Gesundheitsbetreuung","GPT + Vektor-Embedding-DB (Vector Core) — semantische Suche und Antwortgenerierung für Nährstoffe, Krankheiten und Zutaten","Biodaten-verknüpfte Berichtserstellung — personalisierte Ernährungs-/Diät-/Hautpflege-Berichte basierend auf InBody-Daten","Tägliche Mahlzeitfoto-Diagnose — quantitative und qualitative Analyse der Essgewohnheiten","Beratungsverlaufsanalyse — Ableitung persönlicher Gesundheitstrends und Verbesserungsrichtungen"],"techs":["React","PostgreSQL","GPT","Vector DB","Python"]},{"title":"Persönliche Gesundheits-App (GreetingCare)","period":"2025.03 - 2025.09","affiliation":"Hyundai Futurenet","description":"B2C KI-basierte persönliche Gesundheitsmanagement-Web-App. Fördert kontinuierliches Engagement durch Challenge-basierte Belohnungen und unterstützt echte Gesundheitsverbesserungen.","highlights":["Nahrungsergänzungsmittel-Verwaltung — Registrierung, Einnahmehistorie und Vorsichtsmaßnahmen","Ernährungsaufzeichnung & KI-Analyse — tägliches Ernährungsprotokoll mit Nährstoffbilanz-Visualisierung","Gesundheits-Challenges & Belohnungen — Gehen, Trinken usw. + Punktesammlung","Gesundheitsinhalte — regelmäßige Kartenews-Gesundheitsinformationen","Personalisiertes Feedback — Ernährungs- und Lebensstilverbesserungen aus aufgezeichneten Daten"],"techs":["React","AWS","Node.js","AI"]},{"title":"Alt for U (Auto-Alternativtext-Lösung)","period":"2024.05 - 2024.09","affiliation":"Hyundai Futurenet","description":"GPT-basiertes automatisches Alternativtext-Generierungssystem für Web-Zugänglichkeit für Sehbehinderte. Eigenständig geplant und auf der Greeting-Homepage im Live-Betrieb eingesetzt.","highlights":["GPT-basierte Bildbeschreibung — Analyse von Bildkontext und Umgebungstext für natürlichsprachliche Alternativtexte","Admin-Verwaltungsseite — Überprüfung, Bearbeitung und Neugenerierung von Alt-Texten","Automatisierte Web-Zugänglichkeit — automatische Alt-Text-Einfügung beim Bild-Upload","Inhaltstyp-Optimierung — automatische Anpassung des Beschreibungsstils für Events, Produkte, Banner","Live-Bereitstellung — auf der Greeting-Homepage mit verifizierten Zugänglichkeitsverbesserungen"],"techs":["PostgreSQL","JavaScript","GPT","Python","Web Accessibility"]},{"title":"Hyunique (Styling-Plattform)","period":"2024.03 - 2024.06","affiliation":"Soongsil-Universität","description":"Online-Offline integrierte Styling-Sharing-Plattform. KI, Zahlung, QR und Social Login für produktionsreifes UX.","highlights":["GPT Styling-Chatbot & DALL·E Bildgenerierung — Styling-Empfehlungen in natürlicher Sprache + automatische visuelle Bildgenerierung","Toss Payments Integration — Kaufdesign mit echtem Zahlungsfluss","QR-basierte Produktstilprüfung — Offline-QR-Scan für Styling-Info (Online-Offline-Verknüpfung)","Inception V3 + k-NN ähnliche Produktsuche — KI-bildbasierte ähnliche Produktempfehlungen","Papago API Übersetzungsoptimierung — automatische KR→EN Übersetzung für DALL·E-Genauigkeit","Full-Stack: Kakao/Naver OAuth, AWS HTTPS, Jenkins CI"],"techs":["MySQL","AWS","React","GPT","DALL·E","Jenkins"],"github":"https://github.com/it-e-7/hyunique"},{"title":"TaxMate (Wirtschaftsbildungsplattform)","period":"2022.03 - 2022.12","affiliation":"Soongsil-Universität","description":"Partizipative Wirtschaftsbildungsplattform, die ein Klassenzimmer als virtuellen Staat simuliert — Steuern, Berufe, Banken, Aktien und Gesetze. Maximiert den Bildungseffekt basierend auf Lehrerberatung.","highlights":["Benutzertypspezifische Bildschirmgestaltung — unterschiedliche Dashboards und Funktionen je nach Lehrer-/Schülerrolle","Virtuelles Berufs- und Gehaltssystem — Qualifikationen, Gehalt, Beschäftigungsdauer und Bewerbungsgenehmigung","Bankmodul — Kontobewegungen, Einlagenprodukte und Zinsabwicklung","Börsenmodul — Aktienprodukte, nachrichtenbasierte Kursschwankungen, Kauf/Verkauf","Steuersystem — Definition direkter/indirekter Steuern, automatische Zahlung, Steuerstatistiken","Rechtssystem — lehrergesteuerte Gesetzesregistrierung/-änderung, Schülerzugang"],"techs":["React","Node.js","MongoDB","Bootstrap"],"github":"https://github.com/SSU-Taxmate/taxpayer-Backend"},{"title":"GitTalk (Git-basiertes Echtzeit-Chat-Tool)","period":"2019.03 - 2019.06","affiliation":"Persönliches Projekt","description":"CLI-basiertes Chat-Programm, das Git-Repositories als Datenspeicher und Kollaborationskanal nutzt. Schnelles und leichtgewichtiges Kollaborationswerkzeug ohne separaten Server.","highlights":["Git-basierte Datenspeicherung und Kanalbetrieb — Chat-Nachrichten über Git-Repository ohne separaten Server","Automatisches Branch-Management — automatische Branch-Erstellung und Merge bei Ausführung","CLI-Chat-Oberfläche — direkte Ausführung im Entwicklungsverzeichnis, einfache Befehle für Teamkommunikation","Verschlüsselte Benutzerauthentifizierung","Leistungsoptimierung — Pull/Push schneller als Web Parsing, daher praktisch angewendet"],"techs":["C","Git","MySQL","CLI"],"github":"https://github.com/noino0819/GitTalk"}]',
  '[{"title":"2024 Startup Day","grade":"Hauptpreis","issuer":"Hyundai Futurenet","date":"2024.09","affiliation":"Hyundai Futurenet","description":"KI-Projekt ''Alt for U'' zur Verbesserung der Web-Zugänglichkeit für Sehbehinderte geplant und entwickelt. Automatische Erkennung nicht-standardmäßiger Elemente und Generierung von Alternativtexten. Zuständig für Planung und Frontend-Entwicklung."},{"title":"SeoulTech Creative Capstone Wettbewerb","grade":"Bronze","issuer":"SeoulTech Ingenieurausbildungszentrum","date":"2021.11","affiliation":"Soongsil-Universität","description":"Entwicklungsprojekt für Tilt-Struktur-Drohnensteuerungssystem. Modifizierung der PX4-Flugsteuerungsalgorithmen und -parameter für stabile Steuerung."},{"title":"Soongsil Univ. 2021 IT Software Wettbewerb","grade":"Gold","issuer":"Soongsil-Universität","date":"2021.11","affiliation":"Soongsil-Universität","description":"Steuerbildungs-Web-App ''TaxMate'' geplant und entwickelt. Online-Steuerlernen mit Aktienhandel, Nachrichtensimulation und Gesetzgebungsfunktionen."},{"title":"2020 Open Source Contributhon","grade":"Sonderpreis","issuer":"Gabia","date":"2020.11","affiliation":"Hyundai Futurenet","description":"Beitrag zum Verstärkungslernen-Spiel-KI-Projekt ''rosetta stone''. Hearthstone-Spielsimulation und Verbesserung des Agenten-Lernalgorithmus. Code-Review, Branch-Strategie, Issue-Management und praktische Entwicklungskultur erlernt."}]',
  '[{"title":"The Legend of Zelda: Tears of the Kingdom","platform":"Nintendo Switch","comment":"Eine Welt, in der Spieler durch nahtloses Kartendesign ihre eigene Reise gestalten"},{"title":"Hollow Knight","platform":"PC / Switch","comment":"Der Gipfel des Metroidvania mit immersiver Erkundung"},{"title":"Super Mario Odyssey","platform":"Nintendo Switch","comment":"Eine Konzentration purer Freude"},{"title":"Celeste","platform":"PC / Switch","comment":"Die Erdbeere, die jenseits von Scheitern und Herausforderung wartet"}]',
  '[{"artist":"AKMU (Akdong Musician)","title":"항해 (Sailing)","comment":"Ein Album, das ich jedem auf seiner eigenen Reise widmen möchte"},{"artist":"TAEYEON","title":"Letter To Myself","comment":"Worte, die ich mir selbst sagen möchte"}]',
  '[{"author":"Bernard Werber","titles":["Die Ameisen","Papillon","Gott","Thanatonauten"],"comment":"Wenn ich von der Zukunft träumen will, dann so"}]',
  '[{"label":"Gaming","emoji":"🎮"},{"label":"Musik hören","emoji":"🎵"},{"label":"Lesen","emoji":"📚"},{"label":"Fotografie","emoji":"📷"}]',
  '["Als Kind\nträumte ich vage davon, jemand zu werden, der die Welt verändert.","Während ich darüber nachdachte, wie man die Welt verändern kann,\nwar die Antwort, die mich fand, ''Software''.","Etwas, das jeden gleichermaßen erreichen kann,\nunabhängig von Umgebung oder Bedingungen.","Etwas, das jederzeit und überall kostenlos bereitgestellt werden kann,\ndas sich in unzählige Formen neben dem Benutzer verwandelt\num sein Leben zu unterstützen.","Ich war fasziniert von dieser unendlichen Möglichkeit.","Und so begann ich in der Oberschule\nmeine Reise zum Traum, ein ''weltverändernder Entwickler'' zu werden.","An dich, der heute meinen Reisekoffer geöffnet hat,\nmöchte ich mein liebstes Lied spielen."]'
)
