  '{"name":"Sieon Choi","title":"IT Developer","headline":"Hola, soy Sieon Choi — creo tecnología para una sociedad igualitaria.","bioPoints":[{"emoji":"❤️","text":"Siempre alegre y lleno de energía positiva."},{"emoji":"🧡","text":"Valora la responsabilidad y la conexión con las personas."},{"emoji":"💛","text":"Se esfuerza por ser un desarrollador que construye lógica eficiente."},{"emoji":"💚","text":"Experiencia en comunicación rápida y fluida y colaboración en proyectos de equipo."}],"skills":["Java","Spring Boot","Python","TensorFlow","JavaScript","TypeScript","React","Oracle","MySQL","SQL","Git","SVN"],"contacts":[{"label":"Nacimiento","value":"19 de agosto de 1999","icon":"🙆‍♂️"},{"label":"Correo","value":"noino0819@naver.com","url":"mailto:noino0819@naver.com","icon":"✉️"},{"label":"GitHub","value":"noino0819","url":"https://github.com/noino0819","icon":"😺","tooltip":"¡Ven a ver mi GitHub!"},{"label":"LinkedIn","value":"LinkedIn","url":"https://www.linkedin.com/in/%EC%8B%9C%EC%96%B8-%EC%B5%9C-77b9a5248/","icon":"💼"},{"label":"Blog","value":"Reseña diaria de NOINO","url":"https://blog.naver.com/noino0819","icon":"📝","tooltip":"¡Es un blog personal! Pero desde 2023, he publicado más de 5 días a la semana — una prueba de mi constancia."}]}',
