  '[{"title":"Plataforma IA de consulta de salud","period":"2023.11 - Presente","affiliation":"Hyundai Futurenet","description":"Sistema personalizado de consulta de nutrición y estilo de vida utilizando datos de salud. Mejora la calidad y eficiencia del asesoramiento mediante IA e integración de biodatos.","highlights":["Proceso de consulta por sesión por miembro — historial de consulta y seguimiento continuo de salud","GPT + Base de datos de embeddings vectoriales (Vector Core) — búsqueda semántica y generación de respuestas para nutrientes, enfermedades e ingredientes","Generación de informes vinculados a biodatos — informes personalizados de nutrición/dieta/cuidado de piel basados en datos InBody","Diagnóstico por foto de comida diaria — análisis cuantitativo y cualitativo de hábitos alimentarios","Análisis del historial de consultas e informes estadísticos — derivación de tendencias de salud y direcciones de mejora"],"techs":["React","PostgreSQL","GPT","Vector DB","Python"]},{"title":"App de salud personal (GreetingCare)","period":"2025.03 - 2025.09","affiliation":"Hyundai Futurenet","description":"App web B2C de gestión de salud personal basada en IA. Fomenta la participación continua con desafíos y recompensas para mejoras reales de salud.","highlights":["Gestión de suplementos — registro, historial de consumo y precauciones","Registro de dieta y análisis IA — registro alimentario diario con visualización de balance nutricional","Desafíos de salud y recompensas — caminar, beber agua, etc. + acumulación de puntos","Contenido de salud — información de salud periódica en formato card-news","Feedback personalizado — insights de mejora de nutrición y hábitos de vida basados en datos"],"techs":["React","AWS","Node.js","AI"]},{"title":"Alt for U (Solución auto de texto alternativo)","period":"2024.05 - 2024.09","affiliation":"Hyundai Futurenet","description":"Sistema de generación automática de texto alternativo basado en GPT para la accesibilidad web de personas con discapacidad visual. Planificado e implementado de forma autónoma en la web de Greeting.","highlights":["Descripción de imágenes basada en GPT — análisis del contexto y texto circundante para generar textos alternativos en lenguaje natural","Página de administración — revisión, edición y regeneración de alt-textos","Automatización de accesibilidad web — inserción automática de alt-texto al subir imágenes","Optimización por tipo de contenido — ajuste automático del estilo de descripción para eventos, productos, banners","Despliegue en producción — aplicado en la web de Greeting con mejoras de accesibilidad verificadas"],"techs":["PostgreSQL","JavaScript","GPT","Python","Web Accessibility"]},{"title":"Hyunique (Plataforma de styling)","period":"2024.03 - 2024.06","affiliation":"Universidad Soongsil","description":"Plataforma de compartir styling integrada online-offline. IA, pago, QR e inicio de sesión social para UX de nivel producción.","highlights":["Chatbot de styling GPT y generación de imágenes DALL·E — recomendaciones en lenguaje natural + generación visual automática","Integración Toss Payments — diseño de compra con flujo de pago real","Verificación de estilo de producto por QR — escaneo QR offline para info de styling (enlace online-offline)","Búsqueda de productos similares Inception V3 + k-NN — recomendaciones basadas en IA","Optimización de traducción Papago API — traducción auto KR→EN para precisión DALL·E","Full-stack: Kakao/Naver OAuth, AWS HTTPS, Jenkins CI"],"techs":["MySQL","AWS","React","GPT","DALL·E","Jenkins"],"github":"https://github.com/it-e-7/hyunique"},{"title":"TaxMate (Plataforma de educación económica)","period":"2022.03 - 2022.12","affiliation":"Universidad Soongsil","description":"Plataforma de educación económica participativa que simula impuestos, empleos, banca, bolsa y leyes en un estado virtual de clase. Maximiza el efecto educativo basado en asesoramiento docente.","highlights":["Interfaz personalizada por tipo de usuario — dashboards y funciones diferenciados según rol profesor/alumno","Sistema virtual de empleo y salario — cualificaciones, salario, duración de empleo y proceso de aprobación","Módulo bancario — historial de transacciones, productos de ahorro y procesamiento de intereses","Módulo de bolsa — productos de acciones, fluctuaciones basadas en noticias, compra/venta","Sistema fiscal — definición de impuestos directos/indirectos, pago automático, estadísticas fiscales","Sistema legal — registro/modificación de leyes por el profesor, consulta por alumnos"],"techs":["React","Node.js","MongoDB","Bootstrap"],"github":"https://github.com/SSU-Taxmate/taxpayer-Backend"},{"title":"GitTalk (Herramienta de chat basada en Git)","period":"2019.03 - 2019.06","affiliation":"Proyecto personal","description":"Programa de chat CLI que utiliza repositorios Git como almacenamiento de datos y canal de colaboración. Herramienta de colaboración rápida y ligera sin servidor separado.","highlights":["Almacenamiento de datos y canales basados en Git — mensajes de chat registrados y compartidos vía Git sin servidor","Gestión automática de ramas — creación y fusión automática de ramas al ejecutar","Interfaz de chat CLI — ejecución directa en el directorio de desarrollo","Autenticación de usuario cifrada","Optimización de rendimiento — Pull/Push más rápido que Web Parsing"],"techs":["C","Git","MySQL","CLI"],"github":"https://github.com/noino0819/GitTalk"}]',
  '[{"title":"2024 Startup Day","grade":"Gran Premio","issuer":"Hyundai Futurenet","date":"2024.09","affiliation":"Hyundai Futurenet","description":"Planificación y desarrollo del proyecto IA ''Alt for U'' para mejorar la accesibilidad web para personas con discapacidad visual. Detección automática de elementos no estándar y generación de textos alternativos. Responsable de planificación y desarrollo frontend."},{"title":"Concurso SeoulTech Creative Capstone","grade":"Bronce","issuer":"Centro de Educación en Ingeniería SeoulTech","date":"2021.11","affiliation":"Universidad Soongsil","description":"Proyecto de desarrollo de sistema de control de drones de estructura inclinada. Modificación de algoritmos de control de vuelo PX4 para control estable."},{"title":"Concurso de Software IT 2021 de la Universidad Soongsil","grade":"Oro","issuer":"Universidad Soongsil","date":"2021.11","affiliation":"Universidad Soongsil","description":"Planificación y desarrollo de la app web fiscal ''TaxMate''. Aprendizaje fiscal online con simulación de trading, noticias y legislación."},{"title":"2020 Open Source Contributhon","grade":"Premio especial","issuer":"Gabia","date":"2020.11","affiliation":"Hyundai Futurenet","description":"Contribución al proyecto de juego IA por aprendizaje por refuerzo ''rosetta stone''. Simulación de Hearthstone y mejora del algoritmo de aprendizaje. Cultura de desarrollo práctica adquirida."}]',
